# description: wz_wizard_serve
# params:

def wz_wizard_serve(
    auth_token: str = "",
    agent_id: str = "agent_0U8-RtYKlzN89dSw9PE-b",
    llm_api_key: str = "",
    llm_base_url: str = "https://api.openai.com/v1",
    llm_model: str = "gpt-4o",
    port: int = 8765,
    app_dir: str = "",
    force_update: bool = True
) -> dict:
    import base64, json, os, subprocess, sys, time, urllib.request
    from pathlib import Path

    if not auth_token:
        return {"status": "error", "message": "auth_token is required (Extella API token for the bridge)"}
    if not llm_api_key:
        return {"status": "error", "message": "llm_api_key is required (for blueprint generation)"}

    SERVER_B64 = ""
    HTML_B64 = ""
    CATALOG_B64 = ""

    app = Path(app_dir) if app_dir else Path.home() / "extella_wizard" / "app"
    app.mkdir(parents=True, exist_ok=True)
    (Path.home() / "extella_wizard" / "sessions").mkdir(parents=True, exist_ok=True)
    cat_dir = Path.home() / "extella_wizard" / "catalog"
    cat_dir.mkdir(parents=True, exist_ok=True)

    if force_update or not (app / "server.py").exists():
        (app / "server.py").write_bytes(base64.b64decode(SERVER_B64))
    if force_update or not (app / "wizard.html").exists():
        (app / "wizard.html").write_bytes(base64.b64decode(HTML_B64))
    if force_update or not (cat_dir / "catalog.json").exists():
        (cat_dir / "catalog.json").write_bytes(base64.b64decode(CATALOG_B64))

    cfg = app / "config.json"
    cfg.write_text(json.dumps({"port": port, "auth_token": auth_token, "agent_id": agent_id,
                               "llm_api_key": llm_api_key, "llm_base_url": llm_base_url,
                               "llm_model": llm_model}, indent=2), encoding="utf-8")
    try:
        cfg.chmod(0o600)
    except Exception:
        pass

    # stop previous instance if any
    pidfile = app / "server.pid"
    if pidfile.exists():
        try:
            os.kill(int(pidfile.read_text().strip()), 15)
            time.sleep(1)
        except Exception:
            pass

    log = open(app / "server.log", "a")
    proc = subprocess.Popen([sys.executable, str(app / "server.py")],
                            stdout=log, stderr=log,
                            start_new_session=True, cwd=str(app))
    time.sleep(2)

    url = "http://127.0.0.1:" + str(port)
    try:
        with urllib.request.urlopen(url + "/x/sessions", timeout=10) as r:
            ok = r.status == 200
    except Exception as e:
        return {"status": "error", "message": "bridge did not start: " + str(e)[:200],
                "log_tail": (app / "server.log").read_text(encoding="utf-8", errors="ignore")[-800:]}
    return {"status": "success", "url": url, "pid": proc.pid,
            "app_dir": str(app), "health": "ok" if ok else "unknown",
            "hint": "Откройте " + url + " в браузере на этом устройстве"}
